const listLeaveRequests = `-- name: ListLeaveRequests :many
SELECT lr.id, lr.company_id, lr.employee_id, lr.leave_type_id, lr.start_date, lr.end_date, lr.days, lr.reason, lr.attachment_path, lr.status, lr.approver_id, lr.approved_at, lr.rejection_reason, lr.created_at, lr.updated_at, lt.name as leave_type_name,
       e.first_name || ' ' || e.last_name as employee_name
FROM leave_requests lr
JOIN leave_types lt ON lt.id = lr.leave_type_id
JOIN employees e ON e.id = lr.employee_id
WHERE lr.company_id = $1
  AND ($2::bigint IS NULL OR lr.employee_id = $2)
  AND ($3::varchar IS NULL OR lr.status = $3)
ORDER BY lr.created_at DESC
LIMIT $4 OFFSET $5
`

