const upsertLeaveBalance = `-- name: UpsertLeaveBalance :one
INSERT INTO leave_balances (company_id, employee_id, leave_type_id, year, earned, used, carried, adjusted)
VALUES ($1, $2, $3, $4, $5, 0, $6, 0)
ON CONFLICT (company_id, employee_id, leave_type_id, year) DO UPDATE SET
    earned = EXCLUDED.earned,
    carried = EXCLUDED.carried,
    updated_at = NOW()
RETURNING id, company_id, employee_id, leave_type_id, year, earned, used, carried, adjusted, updated_at
`

type UpsertLeaveBalanceParams struct {
	CompanyID   int64          `json:"company_id"`
	EmployeeID  int64          `json:"employee_id"`
	LeaveTypeID int64          `json:"leave_type_id"`
	Year        int32          `json:"year"`
	Earned      pgtype.Numeric `json:"earned"`
	Carried     pgtype.Numeric `json:"carried"`
}

func (q *Queries) UpsertLeaveBalance(ctx context.Context, arg UpsertLeaveBalanceParams) (LeaveBalance, error) {
	row := q.db.QueryRow(ctx, upsertLeaveBalance,
		arg.CompanyID,
		arg.EmployeeID,
		arg.LeaveTypeID,
		arg.Year,
		arg.Earned,
		arg.Carried,
	)
	var i LeaveBalance
	err := row.Scan(
		&i.ID,
		&i.CompanyID,
		&i.EmployeeID,
		&i.LeaveTypeID,
		&i.Year,
		&i.Earned,
		&i.Used,
		&i.Carried,
		&i.Adjusted,
		&i.UpdatedAt,
	)
	return i, err
}
